import React, { useState, useEffect, useCallback, useRef } from 'react';
import './App.css';
import { 
  Phone, Users, BarChart3, History, Settings, Ban, 
  Play, Pause, RefreshCw, AlertCircle, CheckCircle, 
  Mic, MicOff, Upload, Download, Search, Plus,
  Edit, Trash2, X, ChevronLeft, ChevronRight,
  Sun, Moon, Volume2, VolumeX, Wifi, WifiOff,
  PhoneCall, PhoneOff, User, Building, Mail, Calendar
} from 'lucide-react';
import axios from 'axios';
import { Chart as ChartJS, CategoryScale, LinearScale, PointElement, LineElement, BarElement, ArcElement, Title, Tooltip, Legend } from 'chart.js';
import { Line, Bar, Doughnut } from 'react-chartjs-2';

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, BarElement, ArcElement, Title, Tooltip, Legend);

const API_BASE_URL = 'http://localhost:8000';
const WS_URL = 'ws://localhost:8000/ws';

function App() {
  const [activeTab, setActiveTab] = useState('bots');
  const [theme, setTheme] = useState(localStorage.getItem('theme') || 'dark');
  const [refreshInterval, setRefreshInterval] = useState(5000);
  const [notifications, setNotifications] = useState({ sound: true, desktop: true });
  const [isConnected, setIsConnected] = useState(false);

  const [bots, setBots] = useState([]);
  const [campaigns, setCampaigns] = useState([]);
  const [leads, setLeads] = useState([]);
  const [calls, setCalls] = useState([]);
  const [activeCalls, setActiveCalls] = useState([]);
  const [dncList, setDncList] = useState([]);
  const [stats, setStats] = useState({
    activeCalls: 0,
    idleBots: 0,
    connectionRate: 0,
    dropRate: 0,
    dialRatio: 1.0
  });

  // Bot pool management
  const [desiredBotCount, setDesiredBotCount] = useState(6);
  const [actualRunningBots, setActualRunningBots] = useState(0);
  const [isAdjustingPool, setIsAdjustingPool] = useState(false);

  const [searchQuery, setSearchQuery] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedItem, setSelectedItem] = useState(null);
  const [modalType, setModalType] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const wsRef = useRef(null);
  const audioRef = useRef(null);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    // Delay initial fetch to ensure API is ready
    setTimeout(() => {
      connectWebSocket();
      fetchInitialData();
    }, 1000);

    const interval = setInterval(fetchInitialData, refreshInterval);

    return () => {
      clearInterval(interval);
      if (wsRef.current) {
        wsRef.current.close();
      }
    };
  }, [refreshInterval]);

  useEffect(() => {
    const handleKeyPress = (e) => {
      if (e.ctrlKey && e.key >= '1' && e.key <= '7') {
        const tabs = ['bots', 'campaigns', 'leads', 'calls', 'analytics', 'dnc', 'settings'];
        const index = parseInt(e.key) - 1;
        if (tabs[index]) {
          setActiveTab(tabs[index]);
        }
      }
    };

    window.addEventListener('keydown', handleKeyPress);
    return () => window.removeEventListener('keydown', handleKeyPress);
  }, []);

  const connectWebSocket = () => {
    try {
      wsRef.current = new WebSocket(WS_URL);

      wsRef.current.onopen = () => {
        setIsConnected(true);
        showNotification('Connected to server', 'success');
      };

